from collections import deque
from typing import List

class Solution:
    def shortestAlternatingPaths(self, n: int, redEdges: List[List[int]], blueEdges: List[List[int]]) -> List[int]:
        graph = [[] for _ in range(n)]
        for u, v in redEdges:
            graph[u].append((v, 0))
        for u, v in blueEdges:
            graph[u].append((v, 1))

        queue = deque([(0, 0, 0), (0, 1, 0)])
        visited = [[False, False] for _ in range(n)]
        visited[0] = [True, True]
        answer = [-1] * n

        while queue:
            node, color, step = queue.popleft()
            if answer[node] == -1 or answer[node] > step:
                answer[node] = step
            for neighbor, neighbor_color in graph[node]:
                if not visited[neighbor][neighbor_color]:
                    visited[neighbor][neighbor_color] = True
                    if neighbor_color != color:
                        queue.append((neighbor, neighbor_color, step + 1))

        return answer
